-- ============================================
-- REFERENCE DATA
-- ============================================

CREATE TABLE IF NOT EXISTS teams (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  flag        TEXT,
  color       TEXT,
  color_dark  TEXT,
  accent      TEXT
);

CREATE TABLE IF NOT EXISTS players (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  full_name   TEXT,
  num         INTEGER,
  pos         TEXT,
  team_id     TEXT,
  overall     INTEGER,
  face_url    TEXT,
  height      INTEGER,
  weight      INTEGER,
  foot        TEXT,
  birth_date  TEXT,
  birth_place TEXT,
  bio         TEXT,
  club        TEXT
);

CREATE TABLE IF NOT EXISTS stadiums (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  flag        TEXT,
  color       TEXT,
  color_dark  TEXT
);

CREATE TABLE IF NOT EXISTS venues (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  flag        TEXT,
  color       TEXT,
  color_dark  TEXT
);

CREATE TABLE IF NOT EXISTS cards (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  card_type   TEXT NOT NULL CHECK (card_type IN ('player', 'stadium', 'venue')),
  team_id     TEXT,
  bg          TEXT,
  is_special  BOOLEAN DEFAULT FALSE
);

-- ============================================
-- USER PROFILES (extends Supabase auth.users)
-- ============================================

CREATE TABLE IF NOT EXISTS profiles (
  id            UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  username      TEXT UNIQUE,
  display_name  TEXT,
  avatar_url    TEXT,
  country       TEXT,
  badge_tier    TEXT DEFAULT 'bronze' CHECK (badge_tier IN ('bronze', 'silver', 'gold', 'platinum')),
  reputation    INTEGER DEFAULT 100 CHECK (reputation BETWEEN 0 AND 100),
  created_at    TIMESTAMPTZ DEFAULT NOW(),
  updated_at    TIMESTAMPTZ DEFAULT NOW()
);

-- Auto-create profile on signup
CREATE OR REPLACE FUNCTION handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  VALUES (
    NEW.id,
    NEW.raw_user_meta_data->>'full_name',
    NEW.raw_user_meta_data->>'full_name',
    NEW.raw_user_meta_data->>'avatar_url'
  );
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION handle_new_user();

-- ============================================
-- USER COLLECTIONS
-- ============================================

CREATE TABLE IF NOT EXISTS user_collections (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id       UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  card_id       TEXT NOT NULL,
  is_duplicate  BOOLEAN DEFAULT FALSE,
  collected_at  TIMESTAMPTZ DEFAULT NOW(),
  source        TEXT DEFAULT 'pack' CHECK (source IN ('pack', 'trade', 'starter')),
  UNIQUE (user_id, card_id, is_duplicate)
);

CREATE INDEX IF NOT EXISTS idx_collections_user ON user_collections(user_id);
CREATE INDEX IF NOT EXISTS idx_collections_card ON user_collections(card_id);

-- ============================================
-- PACKS
-- ============================================

CREATE TABLE IF NOT EXISTS user_packs (
  user_id       UUID PRIMARY KEY REFERENCES profiles(id) ON DELETE CASCADE,
  quantity      INTEGER DEFAULT 5 CHECK (quantity >= 0),
  total_opened  INTEGER DEFAULT 0,
  updated_at    TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================
-- TRADE SYSTEM
-- ============================================

CREATE TABLE IF NOT EXISTS trade_listings (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id       UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  card_id       TEXT NOT NULL,
  card_name     TEXT NOT NULL,
  team_name     TEXT,
  looking_for   TEXT,
  is_active     BOOLEAN DEFAULT TRUE,
  created_at    TIMESTAMPTZ DEFAULT NOW(),
  updated_at    TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_listings_active ON trade_listings(is_active, created_at DESC) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_listings_user ON trade_listings(user_id);

CREATE TABLE IF NOT EXISTS trade_offers (
  id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  from_user_id        UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  to_user_id          UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  listing_id          UUID,
  requested_card_id   TEXT NOT NULL,
  requested_card_name TEXT NOT NULL,
  offered_card_id     TEXT NOT NULL,
  offered_card_name   TEXT NOT NULL,
  status              TEXT DEFAULT 'pending' CHECK (status IN ('pending', 'accepted', 'rejected', 'cancelled', 'completed')),
  created_at          TIMESTAMPTZ DEFAULT NOW(),
  updated_at          TIMESTAMPTZ DEFAULT NOW(),
  completed_at        TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS idx_trades_from_user ON trade_offers(from_user_id, status);
CREATE INDEX IF NOT EXISTS idx_trades_to_user ON trade_offers(to_user_id, status);

-- ============================================
-- BADGES
-- ============================================

CREATE TABLE IF NOT EXISTS badges (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id     UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  badge_type  TEXT NOT NULL,
  earned_at   TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (user_id, badge_type)
);

CREATE INDEX IF NOT EXISTS idx_badges_user ON badges(user_id);

-- ============================================
-- NOTIFICATIONS
-- ============================================

CREATE TABLE IF NOT EXISTS notifications (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id       UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  type          TEXT NOT NULL CHECK (type IN ('trade_request', 'trade_accepted', 'trade_rejected', 'trade_completed', 'badge_earned')),
  title         TEXT NOT NULL,
  body          TEXT,
  reference_id  UUID,
  is_read       BOOLEAN DEFAULT FALSE,
  created_at    TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_notifications_user ON notifications(user_id, is_read, created_at DESC);

-- ============================================
-- ROW LEVEL SECURITY
-- ============================================

ALTER TABLE profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE user_collections ENABLE ROW LEVEL SECURITY;
ALTER TABLE user_packs ENABLE ROW LEVEL SECURITY;
ALTER TABLE trade_listings ENABLE ROW LEVEL SECURITY;
ALTER TABLE trade_offers ENABLE ROW LEVEL SECURITY;
ALTER TABLE badges ENABLE ROW LEVEL SECURITY;
ALTER TABLE notifications ENABLE ROW LEVEL SECURITY;

-- Profiles: users can read all, update only their own
CREATE POLICY "Profiles are viewable by everyone" ON profiles FOR SELECT USING (true);
CREATE POLICY "Users can update own profile" ON profiles FOR UPDATE USING (auth.uid() = id);

-- Collections: users can only see/edit their own
CREATE POLICY "Users can view own collection" ON user_collections FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own collection" ON user_collections FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can delete own collection" ON user_collections FOR DELETE USING (auth.uid() = user_id);

-- Packs: users can only see/edit their own
CREATE POLICY "Users can view own packs" ON user_packs FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can update own packs" ON user_packs FOR UPDATE USING (auth.uid() = user_id);

-- Trade listings: all authenticated users can view active listings
CREATE POLICY "Active listings are viewable by everyone" ON trade_listings FOR SELECT USING (is_active = TRUE);
CREATE POLICY "Users can insert own listing" ON trade_listings FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update own listing" ON trade_listings FOR UPDATE USING (auth.uid() = user_id);
CREATE POLICY "Users can delete own listing" ON trade_listings FOR DELETE USING (auth.uid() = user_id);

-- Trade offers: users can see offers where they're involved, create offers
CREATE POLICY "Users can view own trade offers" ON trade_offers FOR SELECT
  USING (auth.uid() = from_user_id OR auth.uid() = to_user_id);
CREATE POLICY "Users can create trade offers" ON trade_offers FOR INSERT
  WITH CHECK (auth.uid() = from_user_id);
CREATE POLICY "Users can update own trade offers" ON trade_offers FOR UPDATE
  USING (auth.uid() = from_user_id OR auth.uid() = to_user_id);

-- Badges: viewable by everyone, insert by system only
CREATE POLICY "Badges are viewable by everyone" ON badges FOR SELECT USING (true);

-- Notifications: users only see their own
CREATE POLICY "Users can view own notifications" ON notifications FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can update own notifications" ON notifications FOR UPDATE USING (auth.uid() = user_id);

-- Reference data: everyone can read
ALTER TABLE teams ENABLE ROW LEVEL SECURITY;
ALTER TABLE players ENABLE ROW LEVEL SECURITY;
ALTER TABLE cards ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Teams are viewable by everyone" ON teams FOR SELECT USING (true);
CREATE POLICY "Players are viewable by everyone" ON players FOR SELECT USING (true);
CREATE POLICY "Cards are viewable by everyone" ON cards FOR SELECT USING (true);

